from fastapi import APIRouter, status, Depends
from pydantic import BaseModel
from sqlalchemy.orm import Session
from app.core.permissions import require_project_write
from app.db.session import get_db
from app.models.knowledge_item import KnowledgeItem

router = APIRouter(prefix='/api/v1/knowledge', tags=['knowledge'])


class KnowledgeCreate(BaseModel):
    question: str
    answer: str
    tags: list[str] = []


class KnowledgeOut(BaseModel):
    id: int
    question: str
    answer: str
    tags: list[str]
    model_config = {'from_attributes': True}


@router.post('', status_code=status.HTTP_201_CREATED, response_model=KnowledgeOut,
             dependencies=[Depends(require_project_write)])
def create_item(payload: KnowledgeCreate, db: Session = Depends(get_db)):
    item = KnowledgeItem(question=payload.question, answer=payload.answer, tags=payload.tags)
    db.add(item)
    db.commit()
    db.refresh(item)
    return item


@router.get('', response_model=list[KnowledgeOut])
def list_items(q: str = '', db: Session = Depends(get_db)):
    query = db.query(KnowledgeItem)
    if q:
        query = query.filter(
            KnowledgeItem.question.contains(q) | KnowledgeItem.answer.contains(q)
        )
    return query.all()

