    content = open(os.path.join(WEB, 'app', 'knowledge', 'page.tsx'), encoding='utf-8').read()
    assert 'search' in content.lower() or '搜索' in content

def test_api_client_has_knowledge():
    content = open(os.path.join(WEB, 'lib', 'api.ts'), encoding='utf-8').read()
    assert 'knowledge' in content.lower()

