'use client';
import { useEffect, useState } from 'react';
import { listKnowledge, createKnowledge } from '@/lib/api';

type Item = { id: number; question: string; answer: string; tags: string[] };

export default function KnowledgePage() {
  const [items, setItems] = useState<Item[]>([]);
  const [q, setQ] = useState('');
  const [question, setQuestion] = useState('');
  const [answer, setAnswer] = useState('');
  const [tags, setTags] = useState('');

  async function handleSearch(e: React.FormEvent) {
    e.preventDefault();
    const data = await listKnowledge(q);
    setItems(data);
  }

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    await createKnowledge(question, answer, tags.split(',').map(t => t.trim()).filter(Boolean));
    setQuestion(''); setAnswer(''); setTags('');
    const data = await listKnowledge(q);
    setItems(data);
  }

  useEffect(() => { listKnowledge().then(setItems).catch(console.error); }, []);

  return (
    <main style={{ padding: '2rem', fontFamily: 'sans-serif' }}>
      <h1>知识库</h1>
      <form onSubmit={handleSearch} style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
        <input value={q} onChange={e => setQ(e.target.value)} placeholder="搜索问题或答案..." style={{ flex: 1 }} />
        <button type="submit">搜索</button>
      </form>
      <form onSubmit={handleCreate} style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', marginBottom: '1.5rem', maxWidth: '600px' }}>
        <input value={question} onChange={e => setQuestion(e.target.value)} placeholder="问题" required />
        <textarea value={answer} onChange={e => setAnswer(e.target.value)} placeholder="答案" rows={3} required />
        <input value={tags} onChange={e => setTags(e.target.value)} placeholder="标签（逗号分隔）" />
        <button type="submit">添加</button>
      </form>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {items.map(item => (
          <li key={item.id} style={{ borderBottom: '1px solid #eee', padding: '0.75rem 0' }}>
            <strong>Q: {item.question}</strong>
            <p style={{ margin: '0.25rem 0' }}>A: {item.answer}</p>
            <small style={{ color: '#888' }}>{item.tags.join(', ')}</small>
          </li>
        ))}
      </ul>
    </main>
  );
}
